INSERT INTO conversations (id, organization_id, title, agent_id, tags, metadata, message_count, created_at, updated_at) VALUES ('conv_kLmCzK0MqgM6RjNkGuP3A', 'org_T9cQfSFa3_pqxMjSDy09W', 'Welcome to Engram', 'engram', '["welcome", "getting-started"]', '{"system": true, "type": "welcome"}', 1, datetime('now'), datetime('now'));
INSERT INTO messages (id, conversation_id, organization_id, role, content, sequence, metadata, created_at) VALUES ('msg_Wk0a7js6-QLYkXFCAdcx6', 'conv_kLmCzK0MqgM6RjNkGuP3A', 'org_T9cQfSFa3_pqxMjSDy09W', 'assistant', 'Welcome to Engram — your AI''s long-term memory. Here''s how to get started: 1. **Save a conversation**: After a good chat, say "remember this" or "save this conversation." Your AI will store it in Engram. 2. **Recall later**: In any future session, ask "what do you remember about [topic]?" Your AI will search your stored conversations and bring back the context. 3. **Works everywhere**: Engram works across ChatGPT, Claude Code, Cursor, and any MCP-compatible tool. Save something in one, recall it in another. That''s it. Three steps. Your AI now has memory that persists across sessions, projects, and tools. Try it now — have a conversation about something you''re working on, then say "remember this." Tomorrow, ask about it and watch the magic happen.', 0, '{}', datetime('now'));
